80: // ConfigsOfKind extracts configs of the specified kind.
81: func ConfigsOfKind(configs map[ConfigKey]struct{}, kind config.GroupVersionKind) map[ConfigKey]struct{} {
82: 	ret := make(map[ConfigKey]struct{})
83: 
84: 	for conf := range configs {
85: 		if conf.Kind == kind {
86: 			ret[conf] = struct{}{}
87: 		}
88: 	}
89: 
90: 	return ret
91: }
