93: // ConfigNamesOfKind extracts config names of the specified kind.
94: func ConfigNamesOfKind(configs map[ConfigKey]struct{}, kind config.GroupVersionKind) map[string]struct{} {
95: 	ret := sets.New()
96: 
97: 	for conf := range configs {
98: 		if conf.Kind == kind {
99: 			ret.Insert(conf.Name)
100: 		}
101: 	}
102: 
103: 	return ret
104: }
