106: // ConfigStore describes a set of platform agnostic APIs that must be supported
107: // by the underlying platform to store and retrieve Istio configuration.
108: //
109: // Configuration key is defined to be a combination of the type, name, and
110: // namespace of the configuration object. The configuration key is guaranteed
111: // to be unique in the store.
112: //
113: // The storage interface presented here assumes that the underlying storage
114: // layer supports _Get_ (list), _Update_ (update), _Create_ (create) and
115: // _Delete_ semantics but does not guarantee any transactional semantics.
116: //
117: // _Update_, _Create_, and _Delete_ are mutator operations. These operations
118: // are asynchronous, and you might not see the effect immediately (e.g. _Get_
119: // might not return the object by key immediately after you mutate the store.)
120: // Intermittent errors might occur even though the operation succeeds, so you
121: // should always check if the object store has been modified even if the
122: // mutating operation returns an error.  Objects should be created with
123: // _Create_ operation and updated with _Update_ operation.
124: //
125: // Resource versions record the last mutation operation on each object. If a
126: // mutation is applied to a different revision of an object than what the
127: // underlying storage expects as defined by pure equality, the operation is
128: // blocked.  The client of this interface should not make assumptions about the
129: // structure or ordering of the revision identifier.
130: //
131: // Object references supplied and returned from this interface should be
132: // treated as read-only. Modifying them violates thread-safety.
133: type ConfigStore interface {
134: 	// Schemas exposes the configuration type schema known by the config store.
135: 	// The type schema defines the bidirectional mapping between configuration
136: 	// types and the protobuf encoding schema.
137: 	Schemas() collection.Schemas
138: 
139: 	// Get retrieves a configuration element by a type and a key
140: 	Get(typ config.GroupVersionKind, name, namespace string) *config.Config
141: 
142: 	// List returns objects by type and namespace.
143: 	// Use "" for the namespace to list across namespaces.
144: 	List(typ config.GroupVersionKind, namespace string) ([]config.Config, error)
145: 
146: 	// Create adds a new configuration object to the store. If an object with the
147: 	// same name and namespace for the type already exists, the operation fails
148: 	// with no side effects.
149: 	Create(config config.Config) (revision string, err error)
150: 
151: 	// Update modifies an existing configuration object in the store.  Update
152: 	// requires that the object has been created.  Resource version prevents
153: 	// overriding a value that has been changed between prior _Get_ and _Put_
154: 	// operation to achieve optimistic concurrency. This method returns a new
155: 	// revision if the operation succeeds.
156: 	Update(config config.Config) (newRevision string, err error)
157: 	UpdateStatus(config config.Config) (newRevision string, err error)
158: 
159: 	// Patch applies only the modifications made in the PatchFunc rather than doing a full replace. Useful to avoid
160: 	// read-modify-write conflicts when there are many concurrent-writers to the same resource.
161: 	Patch(orig config.Config, patchFn config.PatchFunc) (string, error)
162: 
163: 	// Delete removes an object from the store by key
164: 	// For k8s, resourceVersion must be fulfilled before a deletion is carried out.
165: 	// If not possible, a 409 Conflict status will be returned.
166: 	Delete(typ config.GroupVersionKind, name, namespace string, resourceVersion *string) error
167: }
