171: // ConfigStoreCache is a local fully-replicated cache of the config store.  The
172: // cache actively synchronizes its local state with the remote store and
173: // provides a notification mechanism to receive update events. As such, the
174: // notification handlers must be registered prior to calling _Run_, and the
175: // cache requires initial synchronization grace period after calling  _Run_.
176: //
177: // Update notifications require the following consistency guarantee: the view
178: // in the cache must be AT LEAST as fresh as the moment notification arrives, but
179: // MAY BE more fresh (e.g. if _Delete_ cancels an _Add_ event).
180: //
181: // Handlers execute on the single worker queue in the order they are appended.
182: // Handlers receive the notification event and the associated object.  Note
183: // that all handlers must be registered before starting the cache controller.
184: type ConfigStoreCache interface {
185: 	ConfigStore
186: 
187: 	// RegisterEventHandler adds a handler to receive config update events for a
188: 	// configuration type
189: 	RegisterEventHandler(kind config.GroupVersionKind, handler EventHandler)
190: 
191: 	// Run until a signal is received
192: 	Run(stop <-chan struct{})
193: 	SetWatchErrorHandler(func(r *cache.Reflector, err error)) error
194: 
195: 	// HasSynced returns true after initial cache synchronization is complete
196: 	HasSynced() bool
197: }
