219: // ResolveShortnameToFQDN uses metadata information to resolve a reference
220: // to shortname of the service to FQDN
221: func ResolveShortnameToFQDN(hostname string, meta config.Meta) host.Name {
222: 	out := hostname
223: 	// Treat the wildcard hostname as fully qualified. Any other variant of a wildcard hostname will contain a `.` too,
224: 	// and skip the next if, so we only need to check for the literal wildcard itself.
225: 	if hostname == "*" {
226: 		return host.Name(out)
227: 	}
228: 
229: 	// if the hostname is a valid ipv4 or ipv6 address, do not append domain or namespace
230: 	if net.ParseIP(hostname) != nil {
231: 		return host.Name(out)
232: 	}
233: 
234: 	// if FQDN is specified, do not append domain or namespace to hostname
235: 	if !strings.Contains(hostname, ".") {
236: 		if meta.Namespace != "" {
237: 			out = out + "." + meta.Namespace
238: 		}
239: 
240: 		// FIXME this is a gross hack to hardcode a service's domain name in kubernetes
241: 		// BUG this will break non kubernetes environments if they use shortnames in the
242: 		// rules.
243: 		if meta.Domain != "" {
244: 			out = out + ".svc." + meta.Domain
245: 		}
246: 	}
247: 
248: 	return host.Name(out)
249: }
250: 
251: // resolveGatewayName uses metadata information to resolve a reference
252: // to shortname of the gateway to FQDN
253: func resolveGatewayName(gwname string, meta config.Meta) string {
254: 	out := gwname
255: 
256: 	// New way of binding to a gateway in remote namespace
257: 	// is ns/name. Old way is either FQDN or short name
258: 	if !strings.Contains(gwname, "/") {
259: 		if !strings.Contains(gwname, ".") {
260: 			// we have a short name. Resolve to a gateway in same namespace
261: 			out = meta.Namespace + "/" + gwname
262: 		} else {
263: 			// parse namespace from FQDN. This is very hacky, but meant for backward compatibility only
264: 			// This is a legacy FQDN format. Transform name.ns.svc.cluster.local -> ns/name
265: 			i := strings.Index(gwname, ".")
266: 			fqdn := strings.Index(gwname[i+1:], ".")
267: 			if fqdn == -1 {
268: 				out = gwname[i+1:] + "/" + gwname[:i]
269: 			} else {
270: 				out = gwname[i+1:i+1+fqdn] + "/" + gwname[:i]
271: 			}
272: 		}
273: 	} else {
274: 		// remove the . from ./gateway and substitute it with the namespace name
275: 		i := strings.Index(gwname, "/")
276: 		if gwname[:i] == "." {
277: 			out = meta.Namespace + "/" + gwname[i+1:]
278: 		}
279: 	}
280: 	return out
281: }
