283: // MostSpecificHostMatch compares the map of the stack to the needle, and returns the longest element
284: // matching the needle, or false if no element in the map matches the needle.
285: func MostSpecificHostMatch(needle host.Name, m map[host.Name][]*config.Config) (host.Name, bool) {
286: 	matches := []host.Name{}
287: 
288: 	// exact match first
289: 	if m != nil {
290: 		if _, ok := m[needle]; ok {
291: 			return needle, true
292: 		}
293: 	}
294: 
295: 	if needle.IsWildCarded() {
296: 		for h := range m {
297: 			// both needle and h are wildcards
298: 			if h.IsWildCarded() {
299: 				if len(needle) < len(h) {
300: 					continue
301: 				}
302: 				if strings.HasSuffix(string(needle[1:]), string(h[1:])) {
303: 					matches = append(matches, h)
304: 				}
305: 			}
306: 		}
307: 	} else {
308: 		for h := range m {
309: 			// only n is wildcard
310: 			if h.IsWildCarded() {
311: 				if strings.HasSuffix(string(needle), string(h[1:])) {
312: 					matches = append(matches, h)
313: 				}
314: 			}
315: 		}
316: 	}
317: 	if len(matches) > 1 {
318: 		// Sort the host names, find the most specific one.
319: 		sort.Sort(host.Names(matches))
320: 	}
321: 	if len(matches) > 0 {
322: 		// TODO: return closest match out of all non-exact matching hosts
323: 		return matches[0], true
324: 	}
325: 	return "", false
326: }
327: 
328: // MostSpecificHostMatch2 compares the map of the stack to the needle, and returns the longest element
329: // matching the needle, or false if no element in the map matches the needle.
330: // TODO: merge with MostSpecificHostMatch once go 1.18 is used
331: func MostSpecificHostMatch2(needle host.Name, m map[host.Name]struct{}) (host.Name, bool) {
332: 	matches := []host.Name{}
333: 
334: 	// exact match first
335: 	if m != nil {
336: 		if _, ok := m[needle]; ok {
337: 			return needle, true
338: 		}
339: 	}
340: 
341: 	if needle.IsWildCarded() {
342: 		for h := range m {
343: 			// both needle and h are wildcards
344: 			if h.IsWildCarded() {
345: 				if len(needle) < len(h) {
346: 					continue
347: 				}
348: 				if strings.HasSuffix(string(needle[1:]), string(h[1:])) {
349: 					matches = append(matches, h)
350: 				}
351: 			}
352: 		}
353: 	} else {
354: 		for h := range m {
355: 			// only n is wildcard
356: 			if h.IsWildCarded() {
357: 				if strings.HasSuffix(string(needle), string(h[1:])) {
358: 					matches = append(matches, h)
359: 				}
360: 			}
361: 		}
362: 	}
363: 	if len(matches) > 1 {
364: 		// Sort the host names, find the most specific one.
365: 		sort.Sort(host.Names(matches))
366: 	}
367: 	if len(matches) > 0 {
368: 		// TODO: return closest match out of all non-exact matching hosts
369: 		return matches[0], true
370: 	}
371: 	return "", false
372: }
