374: // istioConfigStore provides a simple adapter for Istio configuration types
375: // from the generic config registry
376: type istioConfigStore struct {
377: 	ConfigStore
378: }
379: 
380: // MakeIstioStore creates a wrapper around a store.
381: // In pilot it is initialized with a ConfigStoreCache, tests only use
382: // a regular ConfigStore.
383: func MakeIstioStore(store ConfigStore) IstioConfigStore {
384: 	return &istioConfigStore{store}
385: }
386: 
387: func (store *istioConfigStore) ServiceEntries() []config.Config {
388: 	serviceEntries, err := store.List(gvk.ServiceEntry, NamespaceAll)
389: 	if err != nil {
390: 		return nil
391: 	}
392: 
393: 	// To ensure the ip allocation logic deterministically
394: 	// allocates the same IP to a service entry.
395: 	sortConfigByCreationTime(serviceEntries)
396: 	return serviceEntries
397: }
398: 
399: // sortConfigByCreationTime sorts the list of config objects in ascending order by their creation time (if available).
400: func sortConfigByCreationTime(configs []config.Config) {
401: 	sort.Slice(configs, func(i, j int) bool {
402: 		// If creation time is the same, then behavior is nondeterministic. In this case, we can
403: 		// pick an arbitrary but consistent ordering based on name and namespace, which is unique.
404: 		// CreationTimestamp is stored in seconds, so this is not uncommon.
405: 		if configs[i].CreationTimestamp == configs[j].CreationTimestamp {
406: 			in := configs[i].Name + "." + configs[i].Namespace
407: 			jn := configs[j].Name + "." + configs[j].Namespace
408: 			return in < jn
409: 		}
410: 		return configs[i].CreationTimestamp.Before(configs[j].CreationTimestamp)
411: 	})
412: }
413: 
414: func (store *istioConfigStore) Gateways(workloadLabels labels.Collection) []config.Config {
415: 	configs, err := store.List(gvk.Gateway, NamespaceAll)
416: 	if err != nil {
417: 		return nil
418: 	}
419: 
420: 	sortConfigByCreationTime(configs)
421: 	out := make([]config.Config, 0)
422: 	for _, cfg := range configs {
423: 		gateway := cfg.Spec.(*networking.Gateway)
424: 		if gateway.GetSelector() == nil {
425: 			// no selector. Applies to all workloads asking for the gateway
426: 			out = append(out, cfg)
427: 		} else {
428: 			gatewaySelector := labels.Instance(gateway.GetSelector())
429: 			if workloadLabels.IsSupersetOf(gatewaySelector) {
430: 				out = append(out, cfg)
431: 			}
432: 		}
433: 	}
434: 	return out
435: }
